import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Cookie from 'cookie-universal';
import Axios, { INSTRUCTORS, ADMIN_INSTRUCTORS } from '../../Api/Api';
import '../../Styles/InstructorsDashboard.css';

export default function InstructorsDashboard() {
  const navigate = useNavigate();
  const cookie = Cookie();

  const [instructors, setInstructors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [currentInstructor, setCurrentInstructor] = useState(null);
  const [formData, setFormData] = useState({
    name: '',
    bio: '',
    specialization: '',
    rating: '',
    experience_years: '',
    avatar: null
  });
  const [formLoading, setFormLoading] = useState(false);

  // التحقق من الأدمن
  useEffect(() => {
    const user = cookie.get('educational-user');
    if (!user) {
      navigate('/login');
      return;
    }
    
    const userData = typeof user === 'string' ? JSON.parse(user) : user;
    if (userData.role !== 'admin') {
      alert('غير مصرح لك بالوصول لهذه الصفحة');
      navigate('/');
      return;
    }

    loadInstructors();
  }, []);

  // جلب المدرسين
  function loadInstructors() {
    setLoading(true);
    Axios.get(`/${INSTRUCTORS}`)
      .then(res => {
        setInstructors(res.data);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  }

  // فتح Modal للإضافة
  function openAddModal() {
    setEditMode(false);
    setCurrentInstructor(null);
    setFormData({
      name: '',
      bio: '',
      specialization: '',
      rating: '',
      experience_years: '',
      avatar: null
    });
    setShowModal(true);
  }

  // فتح Modal للتعديل
  function openEditModal(instructor) {
    setEditMode(true);
    setCurrentInstructor(instructor);
    setFormData({
      name: instructor.name,
      bio: instructor.bio,
      specialization: instructor.specialization,
      rating: instructor.rating,
      experience_years: instructor.experience_years,
      avatar: null
    });
    setShowModal(true);
  }

  // معالجة التغييرات
  function handleChange(e) {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  }

  // معالجة رفع الصورة
  function handleFileChange(e) {
    setFormData({
      ...formData,
      avatar: e.target.files[0]
    });
  }

  // إضافة/تعديل مدرس
 // إضافة/تعديل مدرس
async function handleSubmit(e) {
  e.preventDefault();
  setFormLoading(true);

  try {
    const data = new FormData();
    data.append('name', formData.name);
    data.append('bio', formData.bio);
    data.append('specialization', formData.specialization);
    data.append('rating', formData.rating);
    data.append('experience_years', formData.experience_years);
    
    if (formData.avatar) {
      data.append('avatar', formData.avatar);
    }

    const token = cookie.get('educational-token');

    if (editMode) {
      // تعديل مدرس - استخدام fetch بدلاً من Axios
      const response = await fetch(`http://127.0.0.1:8000/api/admin/instructors/${currentInstructor.id}`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Accept': 'application/json',
        },
        body: (() => {
          const formData = new FormData();
          formData.append('_method', 'PUT');
          formData.append('name', formData.name);
          formData.append('bio', formData.bio);
          formData.append('specialization', formData.specialization);
          formData.append('rating', formData.rating);
          formData.append('experience_years', formData.experience_years);
          if (formData.avatar) {
            formData.append('avatar', formData.avatar);
          }
          return formData;
        })()
      });

      const result = await response.json();

      if (!response.ok) {
        throw new Error(result.message || 'فشل التعديل');
      }

      alert('تم تعديل المدرس بنجاح ✅');
    } else {
      // إضافة مدرس جديد
      const response = await fetch('http://127.0.0.1:8000/api/admin/instructors', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Accept': 'application/json',
        },
        body: data
      });

      const result = await response.json();

      if (!response.ok) {
        throw new Error(result.message || 'فشل الإضافة');
      }

      alert('تم إضافة المدرس بنجاح ✅');
    }

    setShowModal(false);
    loadInstructors();
    setFormLoading(false);
  } catch (error) {
    console.error('Error:', error);
    alert('حدث خطأ: ' + error.message);
    setFormLoading(false);
  }
}

  // حذف مدرس
  async function handleDelete(id, name) {
    if (!window.confirm(`هل أنت متأكد من حذف المدرس "${name}"؟`)) {
      return;
    }

    try {
      await Axios.delete(`/${ADMIN_INSTRUCTORS}/${id}`);
      alert('تم حذف المدرس بنجاح ✅');
      loadInstructors();
    } catch (error) {
      console.error(error);
      alert('حدث خطأ في الحذف');
    }
  }

  if (loading) {
    return (
      <div className="loading-container">
        <div className="spinner"></div>
        <p>جاري التحميل...</p>
      </div>
    );
  }

  return (
    <div className="instructors-dashboard-page">
      {/* Header */}
      <div className="dashboard-header">
        <div className="container">
          <div className="header-content">
            <div>
              <h1>إدارة المدرسين 👨‍🏫</h1>
              <p>إضافة وتعديل وحذف المدرسين</p>
            </div>
            <button onClick={openAddModal} className="add-btn">
              ➕ إضافة مدرس جديد
            </button>
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="dashboard-content">
        <div className="container">
          <div className="stats-cards">
            <div className="stat-card">
              <h3>إجمالي المدرسين</h3>
              <p className="stat-number">{instructors.length}</p>
            </div>
            <div className="stat-card">
              <h3>متوسط التقييم</h3>
              <p className="stat-number">
                {(instructors.reduce((sum, i) => sum + parseFloat(i.rating), 0) / instructors.length).toFixed(1)}
              </p>
            </div>
            <div className="stat-card">
              <h3>متوسط الخبرة</h3>
              <p className="stat-number">
                {Math.round(instructors.reduce((sum, i) => sum + parseInt(i.experience_years), 0) / instructors.length)} سنوات
              </p>
            </div>
          </div>

          <div className="table-container">
            <table className="instructors-table">
              <thead>
                <tr>
                  <th>الصورة</th>
                  <th>الاسم</th>
                  <th>التخصص</th>
                  <th>التقييم</th>
                  <th>الخبرة</th>
                  <th>الكورسات</th>
                  <th>الإجراءات</th>
                </tr>
              </thead>
              <tbody>
                {instructors.map(instructor => (
                  <tr key={instructor.id}>
                    <td>
                      <div className="instructor-avatar-table">
                        <img 
                          src={instructor.avatar || 'https://via.placeholder.com/50'} 
                          alt={instructor.name}
                          onError={(e) => {
                            e.target.src = 'https://via.placeholder.com/50?text=No+Image';
                          }}
                        />
                      </div>
                    </td>
                    <td className="instructor-name-cell">{instructor.name}</td>
                    <td>{instructor.specialization}</td>
                    <td>⭐ {instructor.rating}</td>
                    <td>{instructor.experience_years} سنوات</td>
                    <td className="courses-count-cell">{instructor.courses_count || 0}</td>
                    <td>
                      <div className="action-buttons">
                        <button 
                          onClick={() => openEditModal(instructor)}
                          className="edit-btn"
                          title="تعديل"
                        >
                          ✏️
                        </button>
                        <button 
                          onClick={() => handleDelete(instructor.id, instructor.name)}
                          className="delete-btn"
                          title="حذف"
                        >
                          🗑️
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>{editMode ? '✏️ تعديل المدرس' : '➕ إضافة مدرس جديد'}</h2>
              <button 
                onClick={() => setShowModal(false)} 
                className="close-btn"
              >
                ✖
              </button>
            </div>

            <form onSubmit={handleSubmit} className="instructor-form">
              <div className="form-group">
                <label>اسم المدرس *</label>
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  required
                  placeholder="مثال: د. أحمد محمد"
                />
              </div>

              <div className="form-group">
                <label>التخصص *</label>
                <input
                  type="text"
                  name="specialization"
                  value={formData.specialization}
                  onChange={handleChange}
                  required
                  placeholder="مثال: تطوير الويب"
                />
              </div>

              <div className="form-group">
                <label>النبذة *</label>
                <textarea
                  name="bio"
                  value={formData.bio}
                  onChange={handleChange}
                  required
                  rows="4"
                  placeholder="نبذة تفصيلية عن المدرس..."
                />
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>التقييم (0-5) *</label>
                  <input
                    type="number"
                    name="rating"
                    value={formData.rating}
                    onChange={handleChange}
                    required
                    min="0"
                    max="5"
                    step="0.1"
                    placeholder="4.5"
                  />
                </div>

                <div className="form-group">
                  <label>سنوات الخبرة *</label>
                  <input
                    type="number"
                    name="experience_years"
                    value={formData.experience_years}
                    onChange={handleChange}
                    required
                    min="0"
                    placeholder="10"
                  />
                </div>
              </div>

              <div className="form-group">
                <label>صورة المدرس {editMode && '(اختياري للتعديل)'}</label>
                <input
                  type="file"
                  accept="image/*"
                  onChange={handleFileChange}
                  required={!editMode}
                />
                {editMode && currentInstructor?.avatar && (
                  <div className="current-image">
                    <p>الصورة الحالية:</p>
                    <img 
                      src={currentInstructor.avatar} 
                      alt="Current" 
                      style={{width: '100px', borderRadius: '8px', marginTop: '0.5rem'}}
                    />
                  </div>
                )}
              </div>

              <div className="modal-footer">
                <button 
                  type="button" 
                  onClick={() => setShowModal(false)}
                  className="cancel-btn"
                >
                  إلغاء
                </button>
                <button 
                  type="submit" 
                  className="submit-btn"
                  disabled={formLoading}
                >
                  {formLoading ? 'جاري الحفظ...' : (editMode ? 'حفظ التعديلات' : 'إضافة المدرس')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
